import WavEncoder from './wavEncoder.js'
import Mp3Encoder from './mp3Encoder.js';
var encoder;
var sampleRate;
var numChannels;


self.onmessage = function(event) {
    var data = event.data;
    switch (data.command) {
      case "init":    init(data.config);   break;
      case "record":  record(data.buffer, data.bufferSize); break;
      case "finish":  finish();   break;
      case "encodeWhole": encodeWhole(data.buffer, data.bufferSize, data.encodingType, data.recordingID); break;
    }
  };

function init(config) {
    sampleRate = config.sampleRate
    numChannels = config.numChannels
    encoder = new WavEncoder(sampleRate, numChannels)
    if (config.recordingFormat == 'mp3') (
      encoder = new Mp3Encoder(sampleRate, numChannels)
    )
    self.postMessage("Worker loaded")
}

function record(buffer, bufferSize) {
    encoder.encode(buffer, bufferSize) 
    self.postMessage({"command": "progress"})
}

function finish() {
    const data = encoder.finish()
    self.postMessage({"command": "recordingComplete", "audioData": data})
}

function encodeWhole(buffer, bufferSize, encodingType, recordingID) {
  if (encodingType == "reverse")
    encoder = new WavEncoder(sampleRate, numChannels)
  encoder.encode(buffer, bufferSize)
  const data = encoder.finish()
  self.postMessage({"command": "encodingFinished", 
                    "audioData": data,
                    "encodingType": encodingType,
                    "recordingID": recordingID,
                  })
}
