const min = Math.min;
const max = Math.max;
const sampleBlockSize = 576 //* 2; 

import { lamejs } from "@/utils/lame.all.js";

export default class Mp3Encoder {
    constructor(sampleRate, numChannels) {
        this.sampleRate = sampleRate;
        this.numChannels = numChannels;
        this.numSamples = 0;
        this.dataViews = [];
        this.mp3encoder = new lamejs.Mp3Encoder(numChannels, sampleRate, 256);
    }

    encode(buffer, bufferSize) {
        const leftChannel = buffer[0]
        const rightChannel = buffer[1]
        for (var i = 0; i < bufferSize; i += sampleBlockSize) {
            let leftChunk = this.floatArray2Int32(leftChannel.subarray(i, i + sampleBlockSize));
            let rightChunk = this.floatArray2Int32(rightChannel.subarray(i, i + sampleBlockSize));

            var mp3buf = this.mp3encoder.encodeBuffer(leftChunk, rightChunk);
            if (mp3buf.length > 0) {
                this.dataViews.push(mp3buf);
            }
        }
    }

    floatArray2Int32 (floatbuffer) {
        var int16Buffer = new Int16Array(floatbuffer.length);
        for (var i = 0, len = floatbuffer.length; i < len; i++) {
            if (floatbuffer[i] < 0) {
                int16Buffer[i] = 32768 * floatbuffer[i];
            } else {
                int16Buffer[i] = 32767 * floatbuffer[i];
            }
        }
        return int16Buffer;
    }

    finish() {
        var mp3buf = this.mp3encoder.flush(); 
        if (mp3buf.length > 0) {
            this.dataViews.push(new Int8Array(mp3buf));
        }
        let blob = new Blob(this.dataViews, {type: 'audio/mp3'});
        this.cleanup()

        return blob
    }

    cleanup() {
        delete this.dataViews;
        this.dataViews = []
    }

}
